example.query:
-- 1. Extracting the year and month from each order date
SELECT customer, strftime('%Y', order_date) AS order_year, strftime('%m', order_date) AS order_month FROM Orders;

-- 2. Finding how many days ago each order was placed relative to a fixed date
SELECT customer, order_date, julianday('2024-04-01') - julianday(order_date) AS days_ago FROM Orders;

shared_table.create_sql:
CREATE TABLE Orders (
  id INTEGER PRIMARY KEY,
  customer TEXT,
  order_date TEXT,
  amount INTEGER
);
